/* * This program prompts the user for 5 positive integers and prints * their sum. It fixes the problem of an infitine loop when a non-int is entered */ #include <iostream> using namespace std; int main() { //initialize variables int sum = 0, num = 0, count = 0; //start of while loop while(count < 5){ //body of the loop that will repeat cout << "Enter a positive number:"; cin >> num; //check if cin has gone into a failed state //cin.fail() will return TRUE if it is if(cin.fail()){ cout << "Invalid entry
"; cin.clear();//reset state to "good" cin.ignore(1000,'
');//clear the stream } //if cin is NOT in a failed state, then a number was entered //and we can proceed as usual else{ //check that it is positive if(num<=0) cout << "The integer must be greater than zero!
"; else{ //we will only get here if it is a valid, positive int sum += num;//same as sum = sum + num count++; //increase count by 1 }//end of inner else }//end of outer else }//end of while cout << "The sum of the 5 integers is: " << sum << "
"; return 0; }
